import{_ as l,o as i,c as e,ak as r}from"./chunks/framework.DwHlt8HN.js";const g=JSON.parse('{"title":"分布式场景面试高频问题汇总","description":"","frontmatter":{},"headers":[],"relativePath":"distributed/scenario/interview-summary.md","filePath":"distributed/scenario/interview-summary.md","lastUpdated":1774318215000}'),n={name:"distributed/scenario/interview-summary.md"};function o(s,a,h,t,d,c){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="分布式场景面试高频问题汇总" tabindex="-1">分布式场景面试高频问题汇总 <a class="header-anchor" href="#分布式场景面试高频问题汇总" aria-label="Permalink to “分布式场景面试高频问题汇总”">​</a></h1><p>分布式系统是面试的重头戏。</p><p>很多候选人能在简历上写「熟悉分布式系统」，但问到细节就卡壳了。</p><p>今天汇总分布式场景的面试高频问题，附上回答思路和追问方向。</p><h2 id="问题一-如何保证缓存和数据库一致性" tabindex="-1">问题一：如何保证缓存和数据库一致性？ <a class="header-anchor" href="#问题一-如何保证缓存和数据库一致性" aria-label="Permalink to “问题一：如何保证缓存和数据库一致性？”">​</a></h2><h3 id="回答思路" tabindex="-1">回答思路 <a class="header-anchor" href="#回答思路" aria-label="Permalink to “回答思路”">​</a></h3><p>这道题考察的是 Cache Aside 模式的理解。</p><ol><li><strong>Cache Aside 模式</strong>：读操作 Cache 命中返回，未命中查 DB 写 Cache；写操作先更新 DB，再删缓存（不是更新缓存）</li><li><strong>为什么删而不是更新</strong>：删除代价小，避免脏写</li><li><strong>可能的问题</strong>：并发情况下可能出现短暂不一致</li></ol><h3 id="关键要点" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点" aria-label="Permalink to “关键要点”">​</a></h3><ul><li>读：Cache 命中 → 返回；未命中 → 查 DB → 写 Cache → 返回</li><li>写：更新 DB → 删除 Cache（不是更新）</li><li>不能先删 Cache 再更新 DB，会导致并发时缓存是旧值</li></ul><h3 id="可能的追问" tabindex="-1">可能的追问 <a class="header-anchor" href="#可能的追问" aria-label="Permalink to “可能的追问”">​</a></h3><ul><li>先更新 DB 还是先删 Cache？（答：先更新 DB，再删 Cache）</li><li>延迟双删是什么？（答：删除 Cache 后延迟一段时间再删除一次，防止并发）</li><li>能做到强一致吗？（答：不能，只能做到最终一致，强一致需要分布式事务）</li></ul><h2 id="问题二-分布式-session-如何实现" tabindex="-1">问题二：分布式 Session 如何实现？ <a class="header-anchor" href="#问题二-分布式-session-如何实现" aria-label="Permalink to “问题二：分布式 Session 如何实现？”">​</a></h2><h3 id="回答思路-1" tabindex="-1">回答思路 <a class="header-anchor" href="#回答思路-1" aria-label="Permalink to “回答思路”">​</a></h3><p>考察的是对分布式 Session 方案的理解。</p><ol><li><strong>Session 共享问题</strong>：单机 Session 无法跨机器共享</li><li><strong>Spring Session + Redis</strong>：将 Session 存储到 Redis</li><li><strong>核心原理</strong>：Filter 拦截请求，替换 HttpSession 实现</li></ol><h3 id="关键要点-1" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点-1" aria-label="Permalink to “关键要点”">​</a></h3><ul><li>Session 存在 JVM 内存，集群环境下各节点不共享</li><li>Spring Session 通过 Filter 将 Session 存入 Redis</li><li>使用 <code>@EnableRedisHttpSession</code> 开启</li></ul><h3 id="可能的追问-1" tabindex="-1">可能的追问 <a class="header-anchor" href="#可能的追问-1" aria-label="Permalink to “可能的追问”">​</a></h3><ul><li>Session 数据序列化用什么？（答：推荐 JSON，避免 Java 序列化）</li><li>Session 过期时间和 Redis TTL 怎么保持一致？（答：Spring Session 自动同步）</li><li>Session 和 Token 哪个更好？（答：各有优劣，Session 有状态管理方便，Token 无状态扩展性好）</li></ul><h2 id="问题三-如何设计一个单点登录系统" tabindex="-1">问题三：如何设计一个单点登录系统？ <a class="header-anchor" href="#问题三-如何设计一个单点登录系统" aria-label="Permalink to “问题三：如何设计一个单点登录系统？”">​</a></h2><h3 id="回答思路-2" tabindex="-1">回答思路 <a class="header-anchor" href="#回答思路-2" aria-label="Permalink to “回答思路”">​</a></h3><p>考察的是对 CAS 原理的理解。</p><ol><li><strong>SSO 定义</strong>：一次登录，多处访问</li><li><strong>CAS 流程</strong>：用户访问 A 系统 → 重定向到 CAS Server → 验证用户名密码 → 返回 ST → A 验证 ST</li><li><strong>三个核心票据</strong>：TGT、TGC、ST</li></ol><h3 id="关键要点-2" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点-2" aria-label="Permalink to “关键要点”">​</a></h3><ul><li>CAS Server 统一认证，各系统验证 Ticket</li><li>ST 一次性使用，防止冒用</li><li>TGC 存在浏览器 Cookie，TGT 存在 CAS Server</li></ul><h3 id="可能的追问-2" tabindex="-1">可能的追问 <a class="header-anchor" href="#可能的追问-2" aria-label="Permalink to “可能的追问”">​</a></h3><ul><li>CAS 和 OAuth2 的区别？（答：CAS 专注单点登录，OAuth2 支持授权）</li><li>CAS 如何实现登出？（答：销毁 TGT，各系统收到通知清除 Session）</li><li>CAS 的 ST 为什么设计成一次性的？（答：防止 ST 被截获后冒用）</li></ul><h2 id="问题四-如何实现接口幂等性" tabindex="-1">问题四：如何实现接口幂等性？ <a class="header-anchor" href="#问题四-如何实现接口幂等性" aria-label="Permalink to “问题四：如何实现接口幂等性？”">​</a></h2><h3 id="回答思路-3" tabindex="-1">回答思路 <a class="header-anchor" href="#回答思路-3" aria-label="Permalink to “回答思路”">​</a></h3><p>考察的是对幂等性实现的理解。</p><ol><li><strong>幂等性定义</strong>：多次执行结果一致</li><li><strong>常用方案</strong>：Token 机制、唯一键、状态机</li><li><strong>Token 机制</strong>：提交前获取 Token，请求时携带 Token，服务端删除 Token</li></ol><h3 id="关键要点-3" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点-3" aria-label="Permalink to “关键要点”">​</a></h3><ul><li>插入操作：唯一键冲突捕获</li><li>更新操作：状态机 + 版本号</li><li>删除操作：天然幂等</li><li>Token 机制：Redis 存储 Token，请求前获取，执行时校验并删除</li></ul><h3 id="可能的追问-3" tabindex="-1">可能的追问 <a class="header-anchor" href="#可能的追问-3" aria-label="Permalink to “可能的追问”">​</a></h3><ul><li>POST 请求怎么幂等？（答：Token 机制）</li><li>分布式锁能保证幂等吗？（答：能，但性能损耗大）</li><li>消息队列消费怎么幂等？（答：消息 ID + 业务去重表）</li></ul><h2 id="问题五-如何设计一个分布式任务调度系统" tabindex="-1">问题五：如何设计一个分布式任务调度系统？ <a class="header-anchor" href="#问题五-如何设计一个分布式任务调度系统" aria-label="Permalink to “问题五：如何设计一个分布式任务调度系统？”">​</a></h2><h3 id="回答思路-4" tabindex="-1">回答思路 <a class="header-anchor" href="#回答思路-4" aria-label="Permalink to “回答思路”">​</a></h3><p>考察的是对分布式任务调度的理解。</p><ol><li><strong>分片模式</strong>：大任务拆分为多个小任务并行处理</li><li><strong>防重复执行</strong>：分布式锁 + 状态检查</li><li><strong>任务框架</strong>：ElasticJob、XXL-JOB</li></ol><h3 id="关键要点-4" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点-4" aria-label="Permalink to “关键要点”">​</a></h3><ul><li>分片策略：Hash 分片、范围分片</li><li>分布式锁：保证同一时刻只有一个节点执行</li><li>状态检查：乐观锁 + 状态更新</li></ul><h3 id="可能的追问-4" tabindex="-1">可能的追问 <a class="header-anchor" href="#可能的追问-4" aria-label="Permalink to “可能的追问”">​</a></h3><ul><li>任务失败了怎么办？（答：重试机制 + 失败告警）</li><li>任务超时怎么处理？（答：超时监控 + 中断）</li><li>广播模式和分片模式的区别？（答：广播所有节点都执行，分片每个节点执行一部分）</li></ul><h2 id="问题六-如何实现全链路限流" tabindex="-1">问题六：如何实现全链路限流？ <a class="header-anchor" href="#问题六-如何实现全链路限流" aria-label="Permalink to “问题六：如何实现全链路限流？”">​</a></h2><h3 id="回答思路-5" tabindex="-1">回答思路 <a class="header-anchor" href="#回答思路-5" aria-label="Permalink to “回答思路”">​</a></h3><p>考察的是对分层限流的理解。</p><ol><li><strong>限流层次</strong>：网关层 → 应用层 → 资源层</li><li><strong>限流算法</strong>：滑动窗口、令牌桶、漏桶</li><li><strong>Sentinel 限流</strong>：注解 + 规则配置</li></ol><h3 id="关键要点-5" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点-5" aria-label="Permalink to “关键要点”">​</a></h3><ul><li>网关层：Nginx/Lua，限制总入口流量</li><li>应用层：Sentinel/Hystrix，限制接口 QPS</li><li>资源层：数据库连接池，限制数据库连接</li></ul><h3 id="可能的追问-5" tabindex="-1">可能的追问 <a class="header-anchor" href="#可能的追问-5" aria-label="Permalink to “可能的追问”">​</a></h3><ul><li>滑动窗口和令牌桶的区别？（答：滑动窗口统计一段时间内请求数，令牌桶按固定速率放行）</li><li>限流后返回什么？（答：友好错误、兜底数据、排队）</li><li>Sentinel 和 Hystrix 的区别？（答：Sentinel 是滑动窗口，Hystrix 是滚动窗口）</li></ul><h2 id="问题七-如何设计一个异地多活架构" tabindex="-1">问题七：如何设计一个异地多活架构？ <a class="header-anchor" href="#问题七-如何设计一个异地多活架构" aria-label="Permalink to “问题七：如何设计一个异地多活架构？”">​</a></h2><h3 id="回答思路-6" tabindex="-1">回答思路 <a class="header-anchor" href="#回答思路-6" aria-label="Permalink to “回答思路”">​</a></h3><p>考察的是对单元化架构的理解。</p><ol><li><strong>单元化</strong>：每个地域是独立单元，自包含</li><li><strong>流量路由</strong>：按用户 ID 或地域路由</li><li><strong>数据同步</strong>：单元内强一致，单元间最终一致</li></ol><h3 id="关键要点-6" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点-6" aria-label="Permalink to “关键要点”">​</a></h3><ul><li>单元内：分布式数据库，强一致</li><li>单元间：异步复制，最终一致</li><li>跨单元事务：TCC 或 Saga 模式</li></ul><h3 id="可能的追问-6" tabindex="-1">可能的追问 <a class="header-anchor" href="#可能的追问-6" aria-label="Permalink to “可能的追问”">​</a></h3><ul><li>单元化架构的核心思想是什么？（答：每个单元自包含，数据和流量隔离）</li><li>如何处理跨单元事务？（答：TCC、Saga 或接受最终一致）</li><li>同城双活和异地多活的区别？（答：同城延迟低，异地可应对城市级别灾难）</li></ul><h2 id="问题八-如何处理缓存穿透、击穿、雪崩" tabindex="-1">问题八：如何处理缓存穿透、击穿、雪崩？ <a class="header-anchor" href="#问题八-如何处理缓存穿透、击穿、雪崩" aria-label="Permalink to “问题八：如何处理缓存穿透、击穿、雪崩？”">​</a></h2><h3 id="回答思路-7" tabindex="-1">回答思路 <a class="header-anchor" href="#回答思路-7" aria-label="Permalink to “回答思路”">​</a></h3><p>考察的是对缓存问题的全面理解。</p><ol><li><strong>穿透</strong>：查询不存在的数据 → 布隆过滤器</li><li><strong>击穿</strong>：热点 key 过期 → 互斥锁 / 逻辑过期</li><li><strong>雪崩</strong>：大量 key 同时过期 → 过期时间随机化 + 熔断降级</li></ol><h3 id="关键要点-7" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点-7" aria-label="Permalink to “关键要点”">​</a></h3><ul><li>穿透：布隆过滤器快速判断 key 是否存在</li><li>击穿：互斥锁保证只有一个线程查 DB，逻辑过期不阻塞</li><li>雪崩：过期时间随机化 + 本地缓存兜底 + 熔断降级</li></ul><h3 id="可能的追问-7" tabindex="-1">可能的追问 <a class="header-anchor" href="#可能的追问-7" aria-label="Permalink to “可能的追问”">​</a></h3><ul><li>布隆过滤器为什么不能删除？（答：删除会影响其他 key 的判断）</li><li>互斥锁和逻辑过期的区别？（答：互斥锁数据一致但有等待，逻辑过期无等待但可能返回脏数据）</li><li>如何选择降级策略？（答：根据业务容忍度决定）</li></ul><h2 id="问题九-如何实现分布式链路追踪" tabindex="-1">问题九：如何实现分布式链路追踪？ <a class="header-anchor" href="#问题九-如何实现分布式链路追踪" aria-label="Permalink to “问题九：如何实现分布式链路追踪？”">​</a></h2><h3 id="回答思路-8" tabindex="-1">回答思路 <a class="header-anchor" href="#回答思路-8" aria-label="Permalink to “回答思路”">​</a></h3><p>考察的是对 TraceId 机制的理解。</p><ol><li><strong>TraceId</strong>：请求链路的唯一标识</li><li><strong>SpanId</strong>：每一步的编号</li><li><strong>MDC</strong>：Logback 集成 TraceId</li></ol><h3 id="关键要点-8" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点-8" aria-label="Permalink to “关键要点”">​</a></h3><ul><li>TraceId 在网关生成，在整个链路中传递</li><li>HTTP Header / RPC RpcContext / MQ 消息 Header 传递</li><li>Logback MDC 将 TraceId 写入日志</li></ul><h3 id="可能的追问-8" tabindex="-1">可能的追问 <a class="header-anchor" href="#可能的追问-8" aria-label="Permalink to “可能的追问”">​</a></h3><ul><li>TraceId 怎么生成？（答：UUID 或 Snowflake）</li><li>Skywalking 和 Zipkin 的区别？（答：Skywalking 功能更强，Zipkin 更轻量）</li><li>如何在日志中看到 TraceId？（答：Logback MDC 配置）</li></ul><h2 id="问题十-如何设计一个分库分表方案" tabindex="-1">问题十：如何设计一个分库分表方案？ <a class="header-anchor" href="#问题十-如何设计一个分库分表方案" aria-label="Permalink to “问题十：如何设计一个分库分表方案？”">​</a></h2><h3 id="回答思路-9" tabindex="-1">回答思路 <a class="header-anchor" href="#回答思路-9" aria-label="Permalink to “回答思路”">​</a></h3><p>考察的是对分库分表的理解。</p><ol><li><strong>分片键选择</strong>：选择分布均匀的字段</li><li><strong>ID 生成</strong>：号段模式或雪花算法</li><li><strong>分片中间件</strong>：ShardingSphere、MyCat</li></ol><h3 id="关键要点-9" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点-9" aria-label="Permalink to “关键要点”">​</a></h3><ul><li>分片键：尽量选择 ID 或时间，避免热点</li><li>ID 生成：号段模式批量取，雪花算法不依赖外部</li><li>分片后的问题：跨分片查询、分页</li></ul><h3 id="可能的追问-9" tabindex="-1">可能的追问 <a class="header-anchor" href="#可能的追问-9" aria-label="Permalink to “可能的追问”">​</a></h3><ul><li>雪花算法时钟回拨怎么办？（答：等待、使用上一个 Sequence）</li><li>分库分表后如何做分页查询？（答：Scatter-Gather 并行查询所有分片）</li><li>分库分表后如何做跨库 JOIN？（答：绑定表广播、单库内 JOIN）</li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>分布式场景的面试题，本质上考察的是：</p><ol><li><strong>对问题的理解</strong>：能不能说清楚问题的本质</li><li><strong>对方案的理解</strong>：能不能说清楚方案的原理和取舍</li><li><strong>对细节的掌握</strong>：能不能说出实现的关键点</li></ol><p>背答案是没有用的，理解原理才是关键。</p>',88)])])}const k=l(n,[["render",o]]);export{g as __pageData,k as default};
